export interface AudioConfig {
  sampleRate: number;
  channels: number;
}

export enum ConnectionState {
  DISCONNECTED = 'DISCONNECTED',
  CONNECTING = 'CONNECTING',
  CONNECTED = 'CONNECTED',
  ERROR = 'ERROR',
}

export interface TranscriptItem {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

// Visualizer specific types
export interface VisualizerState {
  volume: number;
  isTalking: boolean;
}

import { Blob } from '@google/genai';

export function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function arrayBufferToBase64(buffer: ArrayBuffer): string {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function createPcmBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    // Clamp values to [-1, 1] range before converting to PCM16
    const sample = Math.max(-1, Math.min(1, data[i]));
    int16[i] = sample < 0 ? sample * 0x8000 : sample * 0x7FFF;
  }
  return {
    data: arrayBufferToBase64(int16.buffer),
    mimeType: 'audio/pcm;rate=16000',
  };
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { ConnectionState, TranscriptItem } from '../types';
import { createPcmBlob, decodeAudioData, base64ToUint8Array } from '../utils/audioUtils';
import { MODEL_NAME, OUTPUT_SAMPLE_RATE, SYSTEM_INSTRUCTION } from '../constants';

export const useLiveSession = () => {
  const [connectionState, setConnectionState] = useState<ConnectionState>(ConnectionState.DISCONNECTED);
  const [transcripts, setTranscripts] = useState<TranscriptItem[]>([]);
  const [volume, setVolume] = useState<number>(0);

  // Audio Contexts & Nodes
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputNodeRef = useRef<GainNode | null>(null);
  const outputNodeRef = useRef<GainNode | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  // Timing & Sources
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Session
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const currentSessionRef = useRef<any>(null); // To store the resolved session for cleanup

  // Transcripts buffer
  const currentInputTransRef = useRef<string>('');
  const currentOutputTransRef = useRef<string>('');

  const cleanupAudio = useCallback(() => {
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    if (inputAudioContextRef.current) {
      inputAudioContextRef.current.close();
      inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
      outputAudioContextRef.current.close();
      outputAudioContextRef.current = null;
    }

    // Stop all playing sources
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  }, []);

  const connect = useCallback(async () => {
    try {
      setConnectionState(ConnectionState.CONNECTING);

      // Initialize Audio Contexts
      inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });

      inputNodeRef.current = inputAudioContextRef.current.createGain();
      outputNodeRef.current = outputAudioContextRef.current.createGain();
      outputNodeRef.current.connect(outputAudioContextRef.current.destination);

      // Get Microphone Stream
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Connect to Gemini Live
      const sessionPromise = ai.live.connect({
        model: MODEL_NAME,
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: SYSTEM_INSTRUCTION,
          inputAudioTranscription: { model: 'gemini-2.5-flash-native-audio-preview-12-2025' }, // Transcription enabled
          outputAudioTranscription: { model: 'gemini-2.5-flash-native-audio-preview-12-2025' },
        },
        callbacks: {
          onopen: () => {
            console.log('Session Opened');
            setConnectionState(ConnectionState.CONNECTED);

            // Setup Audio Processing pipeline
            if (!inputAudioContextRef.current || !streamRef.current) return;

            const source = inputAudioContextRef.current.createMediaStreamSource(streamRef.current);
            const processor = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = processor;

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);

              // Calculate volume for visualizer
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) {
                sum += inputData[i] * inputData[i];
              }
              const rms = Math.sqrt(sum / inputData.length);
              setVolume(rms); // Update volume state for UI

              // Send to Gemini
              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(processor);
            processor.connect(inputAudioContextRef.current.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // 1. Handle Transcripts
            if (message.serverContent?.outputTranscription) {
              currentOutputTransRef.current += message.serverContent.outputTranscription.text;
            } else if (message.serverContent?.inputTranscription) {
              currentInputTransRef.current += message.serverContent.inputTranscription.text;
            }

            if (message.serverContent?.turnComplete) {
              const newTranscripts: TranscriptItem[] = [];
              if (currentInputTransRef.current.trim()) {
                newTranscripts.push({
                  id: Date.now().toString() + '-user',
                  role: 'user',
                  text: currentInputTransRef.current.trim(),
                  timestamp: new Date()
                });
              }
              if (currentOutputTransRef.current.trim()) {
                 newTranscripts.push({
                  id: Date.now().toString() + '-model',
                  role: 'model',
                  text: currentOutputTransRef.current.trim(),
                  timestamp: new Date()
                });
              }

              if (newTranscripts.length > 0) {
                 setTranscripts(prev => [...prev, ...newTranscripts]);
              }

              currentInputTransRef.current = '';
              currentOutputTransRef.current = '';
            }

            // 2. Handle Audio Output
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio && outputAudioContextRef.current && outputNodeRef.current) {
              const ctx = outputAudioContextRef.current;
              // Sync timing
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const audioBytes = base64ToUint8Array(base64Audio);
              const audioBuffer = await decodeAudioData(audioBytes, ctx, OUTPUT_SAMPLE_RATE, 1);

              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outputNodeRef.current);

              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
              });

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }

            // 3. Handle Interruption
             const interrupted = message.serverContent?.interrupted;
             if (interrupted) {
                sourcesRef.current.forEach(source => {
                  try { source.stop(); } catch(e) {}
                });
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
             }
          },
          onclose: () => {
            console.log('Session Closed');
            setConnectionState(ConnectionState.DISCONNECTED);
          },
          onerror: (err) => {
            console.error('Session Error', err);
            setConnectionState(ConnectionState.ERROR);
          }
        }
      });

      sessionPromiseRef.current = sessionPromise;
      sessionPromise.then(s => { currentSessionRef.current = s; });

    } catch (error) {
      console.error(error);
      setConnectionState(ConnectionState.ERROR);
      cleanupAudio();
    }
  }, [cleanupAudio]);

  const disconnect = useCallback(() => {
    if (currentSessionRef.current) {
        // There is no explicit .close() method documented in the standard @google/genai snippets provided,
        // but typically we stop sending audio and let the server/socket close or rely on garbage collection if we drop references.
        // However, looking at the Live API documentation, usually there is a way to end. 
        // For this specific snippets, we just cleanup local resources which closes socket on browser side.
        // In the `onclose` callback we update state.

        // If the library exposes a close, we call it. If not, we destroy the audio context which usually kills the stream.
        // But the snippet says: "When the conversation is finished, use session.close()".
        try {
           currentSessionRef.current.close();
        } catch(e) {
            console.warn("Could not close session gracefully", e);
        }
    }
    cleanupAudio();
    setConnectionState(ConnectionState.DISCONNECTED);
  }, [cleanupAudio]);

  return {
    connect,
    disconnect,
    connectionState,
    transcripts,
    volume,
    isSpeaking: connectionState === ConnectionState.CONNECTED && volume > 0.01 // Simple activity detection
  };
};

import React, { useEffect, useRef } from 'react';

interface OrbVisualizerProps {
  isActive: boolean;
  volume: number; // 0 to 1
  isConnecting: boolean;
}

const OrbVisualizer: React.FC<OrbVisualizerProps> = ({ isActive, volume, isConnecting }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();
  const timeRef = useRef<number>(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const render = () => {
      timeRef.current += 0.01;

      // Resize handling
      if (canvas.width !== canvas.clientWidth || canvas.height !== canvas.clientHeight) {
        canvas.width = canvas.clientWidth;
        canvas.height = canvas.clientHeight;
      }

      const width = canvas.width;
      const height = canvas.height;
      const centerX = width / 2;
      const centerY = height / 2;

      ctx.clearRect(0, 0, width, height);

      // Base radius configuration
      // If connecting, pulse slowly. If active, react to volume. If inactive, small dot.
      let baseRadius = 60;
      let pulseSpeed = 2;
      let color1 = 'rgba(79, 70, 229, 0.6)'; // Indigo
      let color2 = 'rgba(124, 58, 237, 0.4)'; // Violet

      if (isConnecting) {
          baseRadius = 50 + Math.sin(timeRef.current * 4) * 5;
          color1 = 'rgba(234, 179, 8, 0.6)'; // Yellow
      } else if (!isActive) {
          baseRadius = 20;
          color1 = 'rgba(148, 163, 184, 0.2)'; // Slate
          color2 = 'rgba(148, 163, 184, 0.1)';
      } else {
          // Active state logic
          // Map volume (RMS) to radius expansion
          // RMS usually 0.0 to 0.5 for speech
          const expansion = Math.min(volume * 400, 100); 
          baseRadius = 70 + expansion;
      }

      // Draw Outer Glow
      const gradient = ctx.createRadialGradient(centerX, centerY, baseRadius * 0.2, centerX, centerY, baseRadius * 1.5);
      gradient.addColorStop(0, color1);
      gradient.addColorStop(0.6, color2);
      gradient.addColorStop(1, 'rgba(0,0,0,0)');

      ctx.beginPath();
      ctx.arc(centerX, centerY, baseRadius * 1.5, 0, Math.PI * 2);
      ctx.fillStyle = gradient;
      ctx.fill();

      // Draw Inner Core
      ctx.beginPath();
      // Add some noise/wobble to the inner core based on time
      const wobble = isActive ? Math.sin(timeRef.current * 3) * 2 : 0;
      ctx.arc(centerX, centerY, (baseRadius * 0.5) + wobble, 0, Math.PI * 2);
      ctx.fillStyle = 'white';
      ctx.globalAlpha = isActive ? 0.9 : 0.3;
      ctx.shadowBlur = 20;
      ctx.shadowColor = 'white';
      ctx.fill();

      // Reset globals
      ctx.globalAlpha = 1;
      ctx.shadowBlur = 0;

      // Draw "Rings" if active
      if (isActive) {
        ctx.beginPath();
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.2)';
        ctx.lineWidth = 1;
        ctx.arc(centerX, centerY, baseRadius * 1.2, 0, Math.PI * 2);
        ctx.stroke();
      }

      requestRef.current = requestAnimationFrame(render);
    };

    requestRef.current = requestAnimationFrame(render);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isActive, volume, isConnecting]);

  return (
    <canvas 
      ref={canvasRef} 
      className="w-full h-full"
    />
  );
};

export default OrbVisualizer;

import React, { useEffect, useRef } from 'react';
import { TranscriptItem } from '../types';

interface TranscriptLogProps {
  items: TranscriptItem[];
}

const TranscriptLog: React.FC<TranscriptLogProps> = ({ items }) => {
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [items]);

  if (items.length === 0) {
    return (
      <div className="h-full flex items-center justify-center text-slate-500 text-sm italic">
        Awaiting input...
      </div>
    );
  }

  return (
    <div className="flex flex-col space-y-4 p-4">
      {items.map((item) => (
        <div 
          key={item.id} 
          className={`flex flex-col ${item.role === 'user' ? 'items-end' : 'items-start'}`}
        >
          <div 
            className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${
              item.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-sm' 
                : 'bg-slate-800/80 text-slate-200 border border-slate-700/50 rounded-tl-sm'
            }`}
          >
            {item.text}
          </div>
          <span className="text-[10px] text-slate-500 mt-1 px-1">
            {item.role === 'user' ? 'Architect' : 'Cerebral'}
          </span>
        </div>
      ))}
      <div ref={bottomRef} />
    </div>
  );
};

